PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>

SELECT ?attack ?attackLabel ?deaths ?perpetrator ?perpetratorLabel
WHERE {
  ?attack wdt:P31 wd:Q17777672;  # terrorist attack
          wdt:P585 ?time;
          wdt:P276 ?location;
          wdt:P2525 ?deaths;
          wdt:P170 ?perpetrator.


  # Filter Europe: location is European country or within European country
  {
    ?location wdt:P30 wd:Q46.
  }
  UNION
  {
    ?location wdt:P17 ?country.
    ?country wdt:P30 wd:Q46.
  }

  ?perpetrator wdt:P31 wd:Q43229.
  ?attack rdfs:label ?attackLabel.
  FILTER(LANG(?attackLabel) = "en")
  ?perpetrator rdfs:label ?perpetratorLabel.
  FILTER(LANG(?perpetratorLabel) = "en")
  FILTER(?time >= "1980-01-01T00:00:00Z"^^xsd:dateTime)
}
ORDER BY DESC(?deaths)
LIMIT 10

